import "./Navbar.css";

function Navbar() {
  return (
    <nav className="navbar">
      <h2>Finance Tracker</h2>

      <ul>
        <li>Dashboard</li>
        <li>Transactions</li>
        <li>Analytics</li>
      </ul>
    </nav>
  );
}

export default Navbar;
